$css=<<<'CSS'
.zo-game-root--shadow-gardener{max-width:920px;margin:0 auto;padding:20px;border-radius:26px;background:linear-gradient(180deg,#fbf3d5,#dbe7b9);color:#24311f;font-family:"Trebuchet MS","Segoe UI",sans-serif}.zo-game-root--shadow-gardener *{box-sizing:border-box}.sg-top{display:grid;grid-template-columns:repeat(5,1fr);gap:10px;margin-bottom:14px}.sg-stat{background:rgba(255,255,255,.55);border:1px solid rgba(36,49,31,.12);border-radius:14px;padding:10px}.sg-stat strong{display:block;font-size:12px;text-transform:uppercase;color:#627055}.sg-layout{display:grid;grid-template-columns:1.3fr .9fr;gap:14px}.sg-board{display:grid;grid-template-columns:repeat(8,1fr);gap:6px;background:#93b47d;padding:12px;border-radius:20px}.sg-cell{aspect-ratio:1;border-radius:12px;background:#eef7d3;border:1px solid rgba(0,0,0,.08);display:flex;align-items:center;justify-content:center;font-size:24px;cursor:pointer;position:relative}.sg-cell--shadow{background:#c4d7a0}.sg-cell--stone{background:#7c6f66;color:#fff}.sg-cell--seed{box-shadow:inset 0 0 0 2px rgba(53,92,41,.18)}.sg-side{background:rgba(255,255,255,.52);border:1px solid rgba(36,49,31,.12);border-radius:20px;padding:14px}.sg-btns{display:flex;flex-wrap:wrap;gap:8px;margin:12px 0}.sg-btn{border:0;border-radius:12px;padding:10px 14px;background:#4f7c35;color:#fff;font-weight:700;cursor:pointer}.sg-btn--ghost{background:#8b6f47}.sg-log{min-height:82px;font-size:14px;line-height:1.55;color:#4a5b3d}@media (max-width:780px){.sg-layout{grid-template-columns:1fr}.sg-top{grid-template-columns:repeat(2,1fr)}}
CSS;
$js=<<<'JS'
document.addEventListener('DOMContentLoaded',function(){document.querySelectorAll('.zo-game-root--shadow-gardener').forEach(function(root){const boardEl=root.querySelector('[data-board]'),dayEl=root.querySelector('[data-day]'),sunEl=root.querySelector('[data-sun]'),stoneEl=root.querySelector('[data-stones]'),bloomEl=root.querySelector('[data-blooms]'),goalEl=root.querySelector('[data-goal]'),logEl=root.querySelector('[data-log]');const seeds={'1,1':0,'3,2':0,'6,2':0,'2,5':0,'5,6':0,'6,4':0};let state;function key(x,y){return x+','+y}function dirs(){return[{name:'North',dx:0,dy:-1,shadeX:0,shadeY:1},{name:'East',dx:1,dy:0,shadeX:-1,shadeY:0},{name:'South',dx:0,dy:1,shadeX:0,shadeY:-1},{name:'West',dx:-1,dy:0,shadeX:1,shadeY:0}]}function reset(){state={day:1,sunIndex:0,stones:new Set(['4,3','1,4']),plants:JSON.parse(JSON.stringify(seeds)),log:'Plants only grow in shadow. Click empty tiles to place stones and shape the shade.'};render()}function shadows(){const map={};state.stones.forEach(function(k){const p=k.split(','),x=Number(p[0]),y=Number(p[1]),d=dirs()[state.sunIndex];for(let i=1;i<=2;i++){const sx=x+d.shadeX*i,sy=y+d.shadeY*i;if(sx>=0&&sy>=0&&sx<8&&sy<8)map[key(sx,sy)]=true}});return map}function advance(){const shade=shadows();let blooms=0;Object.keys(state.plants).forEach(function(k){if(shade[k])state.plants[k]=Math.min(3,state.plants[k]+1);else state.plants[k]=Math.max(0,state.plants[k]-1);if(state.plants[k]===3)blooms++});state.day++;state.sunIndex=(state.sunIndex+1)%4;state.log=blooms>=4?'The garden is thriving. You shaped enough shadow for a bloom chain.':'The sun moved. Read the new angle and rebuild the shadow.';render()}function blooms(){return Object.values(state.plants).filter(function(v){return v===3}).length}function clickCell(x,y){const k=key(x,y);if(state.plants[k]!==undefined){state.log='Seeds stay in place. Build shade around them.';render();return}if(state.stones.has(k)){state.stones.delete(k);state.log='You removed a stone and reopened the light.'}else if(state.stones.size<6){state.stones.add(k);state.log='A new object now bends the shadow across the bed.'}else{state.log='You can only keep 6 shadow objects at once.'}render()}function render(){const shade=shadows();boardEl.innerHTML='';for(let y=0;y<8;y++){for(let x=0;x<8;x++){const k=key(x,y),cell=document.createElement('button');cell.type='button';cell.className='sg-cell';if(shade[k])cell.classList.add('sg-cell--shadow');if(state.plants[k]!==undefined)cell.classList.add('sg-cell--seed');if(state.stones.has(k)){cell.classList.add('sg-cell--stone');cell.textContent='◼'}if(state.plants[k]!==undefined){const stage=state.plants[k];cell.textContent=stage===0?'•':stage===1?'🌱':stage===2?'🌿':'🌸'}cell.addEventListener('click',function(){clickCell(x,y)});boardEl.appendChild(cell)}}dayEl.textContent=String(state.day);sunEl.textContent=dirs()[state.sunIndex].name;bloomEl.textContent=String(blooms());stoneEl.textContent=state.stones.size+'/6';goalEl.textContent=state.day>10?(blooms()>=4?'Won':'Need 4 blooms'):('4 by day 10');logEl.textContent=state.day>10?(blooms()>=4?'Shadow mastered. Your flowers bloom because you sculpted darkness on purpose.':'Too much light reached the roots. Restart and think two days ahead.') : state.log}root.querySelector('[data-next]').addEventListener('click',advance);root.querySelector('[data-restart]').addEventListener('click',reset);reset()})});
JS;
if(!function_exists('zo_game_shadow_gardener_render')){function zo_game_shadow_gardener_render($post_id=0,$module=array()){ob_start();?>
<div class="zo-game-root zo-game-root--shadow-gardener">
<h2>Shadow Gardener</h2>
